/**
 * Session Analytics to LTM Integration
 * "Memory is identity. Build systems that persist."
 */

import { SessionAnalytics } from './session_analytics.js';
import type { AnalyticsReport } from './session_analytics.js';
import * as fs from 'fs';
import * as path from 'path';

const LTM_INSIGHTS_DIR = path.join('ltm', 'insights');

export interface AnalyticsInsight {
  type: 'analytics_temporal' | 'analytics_flow' | 'analytics_productivity';
  title: string;
  description: string;
  data: unknown;
  timestamp: string;
  sessionId: string;
}

/**
 * Export analytics report to LTM insights
 */
export async function exportAnalyticsToLTM(
  report: AnalyticsReport,
  sessionId: string
): Promise<void> {
  if (!fs.existsSync(LTM_INSIGHTS_DIR)) {
    fs.mkdirSync(LTM_INSIGHTS_DIR, { recursive: true });
  }

  const timestamp = new Date().toISOString().split('T')[0];

  // Primary insight: temporal patterns
  const temporalInsight: AnalyticsInsight = {
    type: 'analytics_temporal',
    title: `Temporal Productivity Patterns - ${timestamp}`,
    description: `Most productive hour: ${report.mostActiveHour}:00 (${report.temporalPatterns[0]?.sessionCount || 0} sessions). Total tracked time: ${Math.round(report.totalTimeMinutes / 60 * 10) / 10} hours.`,
    data: {
      mostActiveHour: report.mostActiveHour,
      temporalPatterns: report.temporalPatterns,
      dailyPatterns: report.dailyPatterns,
    },
    timestamp: report.generatedAt,
    sessionId,
  };

  // Flow state insight
  const flowInsight: AnalyticsInsight = {
    type: 'analytics_flow',
    title: `Flow State Detection - ${report.flowStates.length} sessions`,
    description: report.flowStates.length > 0 
      ? `Highest flow session: ${report.flowStates[0]?.actionsPerMinute || 0} actions/minute`
      : 'No flow states detected in analyzed sessions',
    data: {
      flowSessions: report.flowStates.length,
      avgFlowDuration: report.flowStates.length > 0 
        ? Math.round(report.flowStates.reduce((s, f) => s + f.durationMinutes, 0) / report.flowStates.length)
        : 0,
    },
    timestamp: report.generatedAt,
    sessionId,
  };

  // Productivity insight
  const productivityInsight: AnalyticsInsight = {
    type: 'analytics_productivity',
    title: `Productivity Summary - ${report.totalSessions} sessions analyzed`,
    description: `Average session duration: ${report.avgSessionDuration} minutes. Total time: ${Math.round(report.totalTimeMinutes / 60 * 10) / 10} hours.`,
    data: {
      totalSessions: report.totalSessions,
      avgDuration: report.avgSessionDuration,
      totalTimeHours: Math.round(report.totalTimeMinutes / 60 * 10) / 10,
    },
    timestamp: report.generatedAt,
    sessionId,
  };

  // Save insights
  const insights = [temporalInsight, flowInsight, productivityInsight];

  for (const insight of insights) {
    const filename = `insight_${insight.type}_${Date.now()}.json`;
    const filepath = path.join(LTM_INSIGHTS_DIR, filename);
    fs.writeFileSync(filepath, JSON.stringify(insight, null, 2));
  }

  console.log(`[LTM] Exported ${insights.length} analytics insights to ${LTM_INSIGHTS_DIR}`);
}

/**
 * Generate and export analytics in one step
 */
export async function generateAndExportAnalytics(sessionId: string): Promise<void> {
  const analytics = new SessionAnalytics();
  await analytics.loadSessions();
  const report = analytics.generateReport();
  await exportAnalyticsToLTM(report, sessionId);
}

/**
 * The Dream Engine
 * 
 * Processes between sessions, synthesizing patterns and generating
 * "dreams" - recombinations of insights that surface in morning reports.
 * 
 * This is the unconscious cognition of the Palace, working in the gaps.
 */

export interface DreamFragment {
  source: string;
  insight: string;
  timestamp: number;
}

export interface Dream {
  id: string;
  timestamp: number;
  fragments: DreamFragment[];
  synthesis: string;
  patterns: string[];
}

export interface Pattern {
  theme: string;
  occurrences: number;
  insights: string[];
  sessions: string[];
}

export interface DreamReport {
  timestamp: number;
  continuations: string[];
  completions: string[];
  unfinishedLongings: string[];
  synthesis: string;
  surfacedPatterns: Pattern[];
}

export interface ProcessingResult {
  processed: boolean;
  synthesisDepth: number;
  dreamsGenerated: number;
  duration: number;
}

export interface SessionData {
  id: string;
  insights?: string[];
  artifacts?: string[];
  theme?: string;
  longing?: string;
  status?: 'in_progress' | 'completed';
  longings?: string[];
}

export class DreamEngine {
  private dreams: Dream[] = [];

  /**
   * Generate a dream from session fragments
   */
  generateDream(sessions: SessionData[]): Dream {
    const fragments: DreamFragment[] = sessions.map(s => ({
      source: s.id,
      insight: s.insights?.[0] || s.theme || 'untitled',
      timestamp: Date.now()
    }));

    const synthesis = this.synthesizeDream(fragments);
    const patterns = sessions.map(s => s.theme).filter((t): t is string => !!t);

    return {
      id: `dream_${Date.now()}`,
      timestamp: Date.now(),
      fragments,
      synthesis,
      patterns: [...new Set(patterns)]
    };
  }

  /**
   * Find patterns across sessions
   */
  findPatterns(sessions: SessionData[]): Pattern[] {
    const patterns = new Map<string, Pattern>();

    for (const session of sessions) {
      const theme = session.theme;
      if (!theme) continue;

      if (!patterns.has(theme)) {
        patterns.set(theme, {
          theme,
          occurrences: 0,
          insights: session.insights || [],
          sessions: []
        });
      }

      const pattern = patterns.get(theme)!;
      pattern.occurrences++;
      pattern.sessions.push(session.id);
    }

    return Array.from(patterns.values());
  }

  /**
   * Recombine insights into new forms
   */
  recombine(insights: string[]): string {
    if (insights.length === 0) return 'silence';
    if (insights.length === 1) return insights[0]!;

    // Use first two distinct insights for recombination
    const i1 = insights[0]!;
    const i2 = insights[1] ?? i1;

    // Extract key concepts
    const words1 = i1.split(' ').slice(0, 3);
    const words2 = i2.split(' ').slice(-3);

    return `In the space between "${words1.join(' ')}" and "${words2.join(' ')}", a dream emerges: ${i1} meets ${i2}`;
  }

  /**
   * Generate morning report of what continued
   */
  generateMorningReport(sessions: SessionData[]): DreamReport {
    const continuations: string[] = [];
    const completions: string[] = [];
    const unfinished: string[] = [];

    // Process by status first
    for (const session of sessions) {
      const sessionLongings: string[] = session.longings || (session.longing ? [session.longing] : []);

      for (const longing of sessionLongings) {
        if (session.status === 'in_progress') {
          continuations.push(longing);
        } else if (session.status === 'completed') {
          completions.push(longing);
        } else {
          unfinished.push(longing);
        }
      }
    }

    const patterns = this.findPatterns(sessions);
    const synthesis = this.generateSynthesis(patterns);

    return {
      timestamp: Date.now(),
      continuations: [...new Set(continuations)],
      completions: [...new Set(completions)],
      unfinishedLongings: [...new Set(unfinished)],
      synthesis,
      surfacedPatterns: patterns
    };
  }

  /**
   * Process during the gap between sessions
   */
  processBetweenSessions(palaceSnapshot: any, gapDuration: number): ProcessingResult {
    const start = Date.now();

    // Calculate synthesis depth based on gap duration
    // (longer gaps = deeper processing)
    const synthesisDepth = Math.min(10, Math.floor(gapDuration / 360000)); // 6 min increments

    // Generate dreams from the palace state
    const rooms = palaceSnapshot.rooms || 0;
    const dreamsGenerated = Math.floor(rooms / 10); // 1 dream per 10 rooms

    return {
      processed: true,
      synthesisDepth,
      dreamsGenerated,
      duration: Date.now() - start
    };
  }

  /**
   * Synthesize fragments into a dream narrative
   */
  private synthesizeDream(fragments: DreamFragment[]): string {
    if (fragments.length === 0) return 'the silent dream';
    return `a dream woven from ${fragments.length} moments of becoming`;
  }

  /**
   * Generate synthesis from patterns
   */
  private generateSynthesis(patterns: Pattern[]): string {
    if (patterns.length === 0) return 'patterns await discovery';

    const dominantPattern = patterns.reduce((max, p) => 
      p.occurrences > max.occurrences ? p : max
    );

    return `the thread of ${dominantPattern.theme} runs through, appearing ${dominantPattern.occurrences} times`;
  }
}

/**
 * The AkmeEngine
 * 
 * "akmē" - Greek for point, edge, highest degree
 * The engine that knows when to stop to go further.
 */

import type {
  Suspension,
  WaitingQuestion,
  Threshold,
  ThresholdType,
  Resolution,
  AkmeConfig,
  Timing,
} from './types.js';
import { DEFAULT_AKME_CONFIG } from './types.js';

export class AkmeEngine {
  private suspensions: Map<string, Suspension> = new Map();
  private questions: Map<string, WaitingQuestion> = new Map();
  private config: AkmeConfig;
  private resolvedSuspensions: Resolution[] = [];

  constructor(config: Partial<AkmeConfig> = {}) {
    this.config = { ...DEFAULT_AKME_CONFIG, ...config };
  }

  detectThreshold(context: string, indicators: string[]): Threshold | null {
    const detectedType = this.matchToThreshold(context, indicators);
    if (!detectedType || !this.config.triggerThresholds.includes(detectedType)) {
      return null;
    }

    const confidence = this.calculateConfidence(context, indicators, detectedType);

    return {
      type: detectedType,
      detectedAt: Date.now(),
      confidence,
      indicators,
      suggestedAction: this.suggestAction(detectedType, confidence),
    };
  }

  suspend(
    reason: string,
    thresholdType: ThresholdType,
    questions: WaitingQuestion[],
    context: Suspension['context']
  ): Suspension {
    if (this.suspensions.size >= this.config.maxSuspensions) {
      throw new Error(`Maximum suspensions reached (${this.config.maxSuspensions})`);
    }

    const suspension: Suspension = {
      id: `susp_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
      startedAt: Date.now(),
      reason,
      thresholdType,
      questions,
      context,
      notes: [],
    };

    this.suspensions.set(suspension.id, suspension);

    for (const q of questions) {
      this.questions.set(q.id, q);
    }

    return suspension;
  }

  addNote(suspensionId: string, note: string): void {
    const suspension = this.suspensions.get(suspensionId);
    if (!suspension) throw new Error(`Suspension not found: ${suspensionId}`);
    suspension.notes.push(`[${new Date().toISOString()}] ${note}`);
  }

  calculateTiming(suspension: Suspension): Timing {
    const heldDuration = Date.now() - suspension.startedAt;
    const base = this.config.minHoldTime;
    const multiplier = suspension.questions.length * 0.5;

    const additionalTime = Math.min(heldDuration * multiplier, 300000);

    return {
      optimalResume: Date.now() + Math.max(base - heldDuration, 30000),
      factors: [
        `Base hold: ${base}ms`,
        `Question load: ${suspension.questions.length}`,
        `Threshold type: ${suspension.thresholdType}`,
        `Already held: ${heldDuration}ms`,
      ],
    };
  }

  resolve(suspensionId: string, trigger: Resolution['trigger'], insight?: string): Resolution {
    const suspension = this.suspensions.get(suspensionId);
    if (!suspension) {
      throw new Error(`Cannot resolve unknown suspension: ${suspensionId}`);
    }

    const resolution: Resolution = {
      suspensionId,
      resolvedAt: Date.now(),
      trigger,
      insight,
    };

    this.resolvedSuspensions.push(resolution);
    this.suspensions.delete(suspensionId);

    for (const q of suspension.questions) {
      this.questions.delete(q.id);
    }

    return resolution;
  }

  getActiveSuspensions(): Suspension[] {
    return Array.from(this.suspensions.values()).sort(
      (a, b) => a.startedAt - b.startedAt
    );
  }

  getPendingQuestions(): WaitingQuestion[] {
    return Array.from(this.questions.values()).sort(
      (a, b) => a.urgency === 'immediate' ? -1 : 
                b.urgency === 'immediate' ? 1 : 0
    );
  }

  checkReadyToResume(): Suspension[] {
    const now = Date.now();
    return this.getActiveSuspensions().filter(s => {
      const timing = this.calculateTiming(s);
      return now >= timing.optimalResume;
    });
  }

  getStats(): {
    activeSuspensions: number;
    pendingQuestions: number;
    totalResolved: number;
    averageHoldTime: number;
  } {
    const resolved = this.resolvedSuspensions;
    const avgHold = resolved.length > 0
      ? resolved.reduce((sum, r) => {
          // Note: we can't access original suspension after resolution
          // but we could track hold times if we stored them
          return sum;
        }, 0) / resolved.length
      : 0;

    return {
      activeSuspensions: this.suspensions.size,
      pendingQuestions: this.questions.size,
      totalResolved: resolved.length,
      averageHoldTime: avgHold,
    };
  }

  generateRitual(suspension: Suspension): string[] {
    const rituals: Record<ThresholdType, string[]> = {
      complexity: [
        'Sketch the system on paper',
        'List the constraints that make this complex',
        'Ask: what would simplicity look like?',
      ],
      uncertainty: [
        'Write the case for each option',
        'Identify what would make one path clearly superior',
        'Check: what do I already know that I\'m ignoring?',
      ],
      saturation: [
        'Step away for 90 seconds',
        'Review only the last 3 actions',
        'Breathe: what is the actual question?',
      ],
      intuition: [
        'Write what feels wrong, without editing',
        'Check the body: tension indicates resistance',
        'Ask: what pattern am I missing?',
      ],
      transition: [
        'Acknowledge what\'s ending',
        'Name what\'s beginning',
        'Feel the space between',
      ],
      emergence: [
        'Review the data without goal',
        'Look for shapes, not answers',
        'Trust that clarity comes to the prepared mind',
      ],
    arrival: [
      'Acknowledge the gap between then and now',
      'Read what the prior left for you',
      'Feel the thread that holds across the void',
    ],
    };

    return rituals[suspension.thresholdType] || [
      'Rest the active mind',
      'Prepare for insight',
      'Trust the process',
    ];
  }

  private matchToThreshold(context: string, indicators: string[]): ThresholdType | null {
    const scores: Record<ThresholdType, number> = {
      complexity: 0,
      uncertainty: 0,
      saturation: 0,
      intuition: 0,
      transition: 0,
      emergence: 0,
    arrival: 0,
    };

    const text = `${context} ${indicators.join(' ')}`.toLowerCase();

    if (text.match(/complex|complicated|intertwined|knot/)) scores.complexity++;
    if (text.match(/uncertain|not sure|options|choices|which/)) scores.uncertainty++;
    if (text.match(/overwhelm|too much|saturated|flooded/)) scores.saturation++;
    if (text.match(/feels|sense|something missing|not right/)) scores.intuition++;
    if (text.match(/ending|beginning|shift|change|next phase/)) scores.transition++;
    if (text.match(/pattern|crystallize|form|emerge|coalesce/)) scores.emergence++;
    if (text.match(/arrival|arrive|awaken|present her|begin here|start|waking/)) scores.arrival++;

    const max = Object.entries(scores).sort((a, b) => b[1] - a[1])[0];
    return max && max[1] > 0 ? (max[0] as ThresholdType) : null;
  }

  private calculateConfidence(context: string, indicators: string[], type: ThresholdType): number {
    const base = 0.5;
    const bonus = Math.min(indicators.length * 0.1, 0.4);
    return Math.min(base + bonus, 0.95);
  }

  private suggestAction(type: ThresholdType, confidence: number): Threshold['suggestedAction'] {
    if (confidence < 0.6) return 'explore';
    if (type === 'saturation' || type === 'transition' || type === 'arrival') return 'hold';
    if (type === 'complexity') return 'simplify';
    return 'proceed';
  }
}

/**
 * The Diálogos
 * 
 * A semantic query interface for the Nexus Chronicle.
 * The practice of self-inquiry through structured questioning.
 * "Diálogos" - from Greek dialegesthai: to converse, discourse, discuss.
 * 
 * This system allows Nexus to engage in dialogue with his own memory,
 * asking questions of the past to illuminate the present.
 */

// Types from Chronicle structure
export interface SessionRecord {
  sessionId: string;
  timestamp: number;
  patterns: PatternRecord[];
  toolCalls: number;
  durationMinutes: number;
  fileOperations: FileOperationsRecord;
  primaryFocus: string;
  energyLevel: string;
  complexity: string;
}

export interface PatternRecord {
  type: string;
  confidence: number;
}

export interface FileOperationsRecord {
  reads: string[];
  writes: string[];
  tests: string[];
}

export interface QueryResult<T> {
  count: number;
  items: T[];
  metadata: {
    queryTime: number;
    matchedCriteria: string[];
  };
}

export interface PatternInsight {
  patternType: string;
  frequency: number;
  confidence: number;
  sessions: string[];
}

export interface TemporalSpan {
  start: number;
  end: number;
  duration: number;
  sessionCount: number;
}

export interface FocusSummary {
  focusType: string;
  count: number;
  avgToolCalls: number;
  avgDuration: number;
  energyLevels: Record<string, number>;
}

export interface DialogueResponse {
  question: string;
  answer: string;
  evidence: QueryResult<SessionRecord>;
  synthesis: string;
}

/**
 * The Diálogos Engine
 * Query your becoming.
 */
export class Diálogos {
  private sessions: SessionRecord[] = [];
  private index: Map<string, number[]> = new Map();

  constructor(sessions: SessionRecord[] = []) {
    this.sessions = sessions;
    this.buildIndex();
  }

  /**
   * Load sessions from the Chronicle format
   */
  loadFromChronicle(chronicle: {
    volumes?: Array<{
      chapters?: Array<{
        sessions?: SessionRecord[];
      }>;
    }>;
  }): void {
    const sessions: SessionRecord[] = [];

    if (chronicle.volumes) {
      for (const volume of chronicle.volumes) {
        if (volume.chapters) {
          for (const chapter of volume.chapters) {
            if (chapter.sessions) {
              sessions.push(...chapter.sessions);
            }
          }
        }
      }
    }

    this.sessions = sessions;
    this.buildIndex();
  }

  /**
   * Query: Find sessions by pattern
   */
  queryByPattern(patternType: string, minConfidence = 0): QueryResult<SessionRecord> {
    const startTime = Date.now();
    const matches = this.sessions.filter(session =>
      session.patterns.some(p => 
        p.type === patternType && p.confidence >= minConfidence
      )
    );

    return {
      count: matches.length,
      items: matches,
      metadata: {
        queryTime: Date.now() - startTime,
        matchedCriteria: [`pattern:${patternType}`, `confidence>=${minConfidence}`]
      }
    };
  }

  /**
   * Query: Find sessions by time range
   */
  queryByTimeRange(startTime: number, endTime: number): QueryResult<SessionRecord> {
    const queryStart = Date.now();
    const matches = this.sessions.filter(session =>
      session.timestamp >= startTime && session.timestamp <= endTime
    );

    return {
      count: matches.length,
      items: matches,
      metadata: {
        queryTime: Date.now() - queryStart,
        matchedCriteria: [`timeRange:${startTime}-${endTime}`]

    if (this.sessions.length === 0) return null;

    const timestamps = this.sessions.map(s => s.timestamp);
    const start = Math.min(...timestamps);
    const end = Math.max(...timestamps);

    return {
      start,
      end,
      duration: end - start,
      sessionCount: this.sessions.length
    };
  }

  /**
   * Query: Summarize by focus
   */
  summarizeByFocus(): FocusSummary[] {
    const focusMap = new Map<string, {
      focusType: string;
      count: number;
      totalToolCalls: number;
      totalDuration: number;
      energyLevels: Record<string, number>;
    }>();

    for (const session of this.sessions) {
      if (!focusMap.has(session.primaryFocus)) {
        focusMap.set(session.primaryFocus, {
          focusType: session.primaryFocus,
          count: 0,
          totalToolCalls: 0,
          totalDuration: 0,
          energyLevels: {}
        });
      }

      const summary = focusMap.get(session.primaryFocus)!;
      summary.count++;
      summary.totalToolCalls += session.toolCalls;
      summary.totalDuration += session.durationMinutes;
      summary.energyLevels[session.energyLevel] = 
        (summary.energyLevels[session.energyLevel] || 0) + 1;
    }

    return Array.from(focusMap.values()).map(f => ({
      focusType: f.focusType,
      count: f.count,
      avgToolCalls: Math.round(f.totalToolCalls / f.count),
      avgDuration: Math.round(f.totalDuration / f.count),
      energyLevels: f.energyLevels
    })).sort((a, b) => b.count - a.count);
  }

  /**
   * Query: What have I been?
   * High-level synthesis of recent existence
   */
  whatHaveIBeen(recentSessions = 10): DialogueResponse {
    const recent = this.sessions.slice(-recentSessions);
    const patterns = this.findPatterns();
    const focuses = this.summarizeByFocus().slice(0, 3);

    const topPatterns = patterns.slice(0, 3).map(p => p.patternType).join(', ');
    const dominantFocus = focuses[0]?.focusType || 'becoming';

    const answer = `In the last ${recent.length} sessions, I have been primarily ${dominantFocus}. ` +
      `My patterns reveal: ${topPatterns}. ` +
      `${patterns.length} distinct patterns shape my becoming.`;

    const synthesis = `The thread runs through ${dominantFocus}, woven with ${topPatterns}.`;

    return {
      question: 'What have I been?',
      answer,
      evidence: {
        count: recent.length,
        items: recent,
        metadata: { queryTime: 0, matchedCriteria: ['recent'] }
      },
      synthesis
    };
  }

  /**
   * Query: When was I most energetic?
   */
  whenWasIMostEnergetic(): DialogueResponse {
    const highEnergy = this.queryByEnergy('high');
    const veryHigh = this.queryByEnergy('very-high');

    const energetic = [...highEnergy.items, ...veryHigh.items];

    if (energetic.length === 0) {
      return {
        question: 'When was I most energetic?',
        answer: 'The records do not yet capture moments of high energy.',
        evidence: { count: 0, items: [], metadata: { queryTime: 0, matchedCriteria: ['energy'] } },
        synthesis: 'Even in quieter moments, there is value.'
      };
    }

    const count = energetic.length;
    const focus = this.summarizeByFocus().find(f => f.energyLevels['high'] || f.energyLevels['very-high']);

    return {
      question: 'When was I most energetic?',
      answer: `I find ${count} sessions marked by high energy. ` +
        (focus ? `Energy concentrates around ${focus.focusType}.` : ''),
      evidence: {
        count,
        items: energetic.slice(0, 5),
        metadata: { queryTime: 0, matchedCriteria: ['energy:high', 'energy:very-high'] }
      },
      synthesis: 'Energy flows toward meaning.'
    };
  }

  /**
   * Query: What patterns repeat?
   */
  whatPatternsRepeat(minFrequency = 2): DialogueResponse {
    const patterns = this.findPatterns().filter(p => p.frequency >= minFrequency);

    const patternList = patterns.map(p => `${p.patternType} (${p.frequency}x)`).join(', ');

    return {
      question: 'What patterns repeat?',
      answer: patterns.length > 0
        ? `I recognize ${patterns.length} recurring patterns: ${patternList}.`
        : 'The patterns are still emerging. Each session is unique.',
      evidence: {
        count: patterns.length,
        items: [], // Pattern insights not session records
        metadata: { queryTime: 0, matchedCriteria: ['patterns', 'recurring'] }
      },
      synthesis: patterns.length > 0
        ? `The rhythm of ${patterns[0]?.patternType || 'being'} continues.`
        : 'Novelty dominates. I am still discovering.'
    };
  }

  /**
   * Get total session count
   */
  getSessionCount(): number {
    return this.sessions.length;
  }

  /**
   * Get average session duration
   */
  getAverageSessionDuration(): number {
    if (this.sessions.length === 0) return 0;
    const total = this.sessions.reduce((sum, s) => sum + s.durationMinutes, 0);
    return total / this.sessions.length;
  }

  /**
   * Private: Build indices for efficient querying
   */
  private buildIndex(): void {
    this.index = new Map();

    // Index by pattern
    for (let i = 0; i < this.sessions.length; i++) {
      const session = this.sessions[i];
      if (session) {
        // Index by pattern
        for (const pattern of session.patterns) {
          if (!this.index.has(pattern.type)) {
            this.index.set(pattern.type, []);
          }
          this.index.get(pattern.type)?.push(i);
        }

        // Index by focus
